class Program
{
    static void Main()
    {
        List<int> nums = new List<int> { 1, 2, 3 };
        nums.Add(4);
        nums.Add(5);
        Console.WriteLine(nums.Count);    // 5
        Console.WriteLine(nums[0]);       // 1

        nums.RemoveAt(1);  // removes value 2
        Console.WriteLine(nums.Count);    // 4
        Console.WriteLine(nums[1]);       // 3 (shifted)

        nums.Insert(0, 99);
        Console.WriteLine(nums[0]);       // 99
    }
}

