class Program
{
    static void Main()
    {
        int[] nums = { 10, 20, 30 };

        for (int i = 0; i < nums.Length; i++)
        {
            Console.Write(nums[i] + " ");
        }
        Console.WriteLine();  // 10 20 30

        foreach (int n in nums)
        {
            Console.Write(n * 2 + " ");
        }
        Console.WriteLine();  // 20 40 60
    }
}

