class Program
{
    static void Main()
    {
        int[,] grid = { { 1, 2, 3 }, { 4, 5, 6 } };
        Console.WriteLine(grid[0, 2]);            // 3
        Console.WriteLine(grid.GetLength(0));      // 2 rows
        Console.WriteLine(grid.GetLength(1));      // 3 cols

        int[][] jagged = new int[2][];
        jagged[0] = new int[] { 10, 20 };
        jagged[1] = new int[] { 30, 40, 50 };
        Console.WriteLine(jagged[1][2]);           // 50
        Console.WriteLine(jagged[1].Length);       // 3
    }
}

